void addData(container data)
{
    FWFTextBlockGroupAssign	groupAssign;
    int						i;

    next addData(data);

    if (relationTable == tablenum(FWFTextBlockGroupAssign))
    {
        ttsbegin;
        for (i = conlen(data); i; i--)
        {
            groupAssign = FWFTextBlockGroupAssign::findByGroupIdRefId(relationRangeValue, conPeek(data, i), true);
            groupAssign.Module = this.parmFormRun().args().parmEnum();
            groupAssign.update();
        }
        ttscommit;
    }
}
